// Extrai texto da resposta do Agente 1 (compativel com AI Agent e lmChatAnthropic)
const agentOutput = $input.first().json
let texto = ''
if (agentOutput.output && typeof agentOutput.output === 'string') {
  texto = agentOutput.output  // Formato AI Agent do N8n
} else if (Array.isArray(agentOutput.content)) {
  texto = agentOutput.content.filter(c => c.type === 'text').map(c => c.text).join('\n')
} else if (agentOutput.text) {
  texto = agentOutput.text
} else {
  texto = JSON.stringify(agentOutput)
}

let queryData = { termos: [], query_ilike: '' }
try {
  const limpo = texto.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim()
  const match = limpo.match(/\{[\s\S]*\}/)
  if (match) queryData = JSON.parse(match[0])
} catch(e) {
  const stopwords = new Set(['posso','para','como','que','uma','dos','das','ser','pode','qual','nao','com','por','isso'])
  const problema = $('Webhook').first().json.body.problema || ''
  const palavras = problema.toLowerCase().replace(/[^a-z\s]/g,' ').split(/\s+/).filter(w => w.length >= 5 && !stopwords.has(w)).slice(0,3)
  queryData = { termos: palavras, query_ilike: palavras[0] || 'contrato' }
}

return [{
  json: {
    ...queryData,
    titulo: $('Webhook').first().json.body.titulo,
    problema: $('Webhook').first().json.body.problema,
    descricao: $('Webhook').first().json.body.descricao,
    user: $('Webhook').first().json.body.user,
    parecer_id: $('Webhook').first().json.body.parecer_id
  }
}]

// Formata os resultados do Supabase para o Agente 2
const resultados = $input.all()
const queryNode = $('Formatar Query').first().json

let contexto = ''
let totalEncontrado = 0

if (resultados && resultados.length > 0) {
  const docs = Array.isArray(resultados[0].json) ? resultados[0].json : []
  totalEncontrado = docs.length

  if (docs.length > 0) {
    contexto = docs.map((doc, i) => {
      const tipo = (doc.tipo || 'DOCUMENTO').toUpperCase()
      const numero = doc.numero || ''
      const orgao = doc.orgao || ''
      const data = doc.data_pub || ''
      const texto = doc.conteudo || doc.ementa || ''
      const url = doc.url || ''

      return `[${i+1}] ${tipo} ${numero}\nÓrgão: ${orgao} | Data: ${data}${url ? ' | URL: ' + url : ''}\n\n${texto.substring(0, 2000)}${texto.length > 2000 ? '...' : ''}`
    }).join('\n\n---\n\n')
  }
}

return [{
  json: {
    problema: queryNode.problema,
    titulo: queryNode.titulo,
    descricao: queryNode.descricao,
    user: queryNode.user,
    parecer_id: queryNode.parecer_id,
    termos_buscados: queryNode.termos,
    total_encontrado: totalEncontrado,
    contexto_jurisprudencia: contexto
  }
}]

